import React, { useState } from 'react';
import ProductTypeTable from './components/ProductTypeTable';
import ProductTable from './components/ProductTable';

const sidebarItems = [
  { label: 'Product Type' },
  { label: 'Product' },
  { label: 'Vendor' },
  { label: 'Software Type' },
  { label: 'Software Category' },
  { label: 'Software License Type' },
  { label: 'Asset State' },
  { label: 'Manufacturer' },
];

function App() {
  const [activeTab, setActiveTab] = useState<number>(0);
  const tabs = [
    'Product Type',
    'Product',
    'Vendor',
    'Software Type',
    'Software Category',
    'Software License Type',
    'Asset State',
    'Manufacturer',
  ];

  const renderTabContent = () => {
    switch (activeTab) {
      case 0:
        return <ProductTypeTable />;
      case 1:
        return <ProductTable />;
     
      default:
        return (
          <div className="bg-white rounded-lg shadow-sm p-6 text-gray-700">
            <h2 className="text-lg font-semibold mb-2">{tabs[activeTab]}</h2>
            <p className="text-sm text-gray-500">This section is not implemented yet.</p>
          </div>
        );
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 py-6">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="bg-white rounded-lg shadow-sm mb-6 p-6">
          <div className="flex flex-col md:flex-row md:items-center md:justify-between gap-4 mb-4">
            <h1 className="text-2xl font-semibold text-gray-900">{tabs[activeTab]}</h1>
            <div className="text-sm text-gray-500">
              <span className="text-gray-400">Home</span>
              <span className="mx-2">/</span>
              <span>Customisation - Asset - {tabs[activeTab]}</span>
            </div>
          </div>
          <div className="border-b border-gray-200">
            <nav className="-mb-px flex space-x-8 overflow-x-auto">
              {tabs.map((tabLabel, index) => (
                <button
                  key={tabLabel}
                  onClick={() => setActiveTab(index)}
                  className={`whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm ${
                    activeTab === index
                      ? 'border-blue-500 text-blue-600'
                      : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                  }`}
                >
                  {tabLabel}
                </button>
              ))}
            </nav>
          </div>
        </div>
        {renderTabContent()}
      </div>
    </div>
  );
}

export default App;
